 {"id":"bd-2vr05.15.4.1","title":"task(control): collect baseline profiles + hotspot opportunity matrix for layout/shaping/rescale paths","description":"Capture baselines and profiles for critical pipelines before optimization/degradation work; produce ranked opportunity matrix with confidence/effort scoring.","acceptance_criteria":"1) Baseline metrics and profiler artifacts are stored and reproducible.\\n2) Top hotspots are ranked with explicit opportunity scores.\\n3) Golden output checksums are captured for later isomorphism proofs.","notes":"No optimization changes without this baseline.","status":"closed","priority":1,"issue_type":"task","estimated_minutes":150,"created_at":"2026-02-13T01:41:14.698119264Z","created_by":"ubuntu","updated_at":"2026-02-16T07:25:24.644189865Z","closed_at":"2026-02-16T07:25:24.644169727Z","close_reason":"Baseline profiles collected across all critical pipelines (text shaping, width, cache, layout, render). Hotspot opportunity matrix with 6 ranked items. Top finding: from_run O(n^2) blocks 60fps shaped rendering. docs/perf/baseline_profiles.md created.","source_repo":".","compaction_level":0,"original_size":0,"labels":["hotspots","perf","profiling"],"dependencies":[{"issue_id":"bd-2vr05.15.4.1","depends_on_id":"bd-2vr05.15.4","type":"parent-child","created_at":"2026-02-24T21:26:00Z","created_by":"import","metadata":"{}","thread_id":""}]}
 {"id":"bd-2vr05.15.4.2","title":"task(control): define frame/memory/queue budgets and quality-tier ladder","description":"Define measurable budgets and tier ladder (quality, balanced, fast, emergency) with explicit feature toggles and semantic safety constraints.","acceptance_criteria":"1) Budgets and tier semantics are explicit and testable.\\n2) Tier transitions preserve semantic correctness invariants.\\n3) Documentation maps each tier to enabled/disabled algorithms.","notes":"Budget policy is contract-level; avoid hidden fallback behavior.","status":"closed","priority":1,"issue_type":"task","estimated_minutes":180,"created_at":"2026-02-13T01:41:15.647282265Z","created_by":"ubuntu","updated_at":"2026-02-16T07:36:50.191642167Z","closed_at":"2026-02-16T07:36:50.191623963Z","close_reason":"done","source_repo":".","compaction_level":0,"original_size":0,"labels":["budgets","degradation","quality-tiers"],"dependencies":[{"issue_id":"bd-2vr05.15.4.2","depends_on_id":"bd-2vr05.15.4","type":"parent-child","created_at":"2026-02-24T21:26:00Z","created_by":"import","metadata":"{}","thread_id":""},{"issue_id":"bd-2vr05.15.4.2","depends_on_id":"bd-2vr05.15.4.1","type":"blocks","created_at":"2026-02-24T21:26:00Z","created_by":"import","metadata":"{}","thread_id":""}]}
